                    startActivityForResult(signInIntent, RC_SIGN_IN)
                } catch (e: ApiException) {
                    println("Google sign-in failed: $e")
                }
            }
        }
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        when (requestCode) {
            RC_SIGN_IN -> {
                val task = GoogleSignIn.getClient(this).silentSignIn(data)
                if (task.isSuccessful) {
                    // Get signed-in user's information
                    val account = task.result?.signInAccount
                    handleGoogleLogin(account)
                } else {
                    // Handle login error
                    val error = task.exception
                    println("Google sign-in failed: $error")
                }
            }
        }
    }

